import React from "react";
import "./Profile.css";

export default function Profile() {
  return (
    <div>
      <header>
        <a href="" className="logo">
          Logo
        </a>
        <ul>
            <li><a href="#">Home</a></li>
            <li><a href="#">About</a></li>
            <li><a href="#">Resume</a></li>
            <li><a href="#">ContactMe</a></li>
        </ul>
      </header>
    </div>
  );
}
